}

void MergeList(LinkList& La, LinkList& Lb, LinkList& Lc) {
  pa=La->next;
  pb=Lb->next;
  Lc=pc=La;
  Lc->next=NULL;
  while(pa||pb ){
    if(!pa) {q=pb; pb=pb->next;}
    else if(!pb) {q=pa; pa=pa->next;}
    else if(pa->data<=pb->data) {q=pa; pa=pa->next;}
    else {q=pb; pb=pb->next;}
    q->next = Lc->next; Lc->next = q;
  }
  delete Lb;
}

void Mix(LinkList& La, LinkList& Lb, LinkList& Lc) {
  pa=La->next;pb=Lb->next;
  Lc=pc=La;
  while(pa&&pb){
    if(pa->data==pb->data) { pc->next=pa;pc=pa;pa=pa->next; u=pb;pb=pb->next; delete u;}
    else if(pa->data<pb->data) {u=pa;pa=pa->next; delete u;}
    else {u=pb; pb=pb->next; delete u;}
  }
  while(pa) {u=pa; pa=pa->next; delete u;}
  while(pb) {u=pb; pb=pb->next; delete u;}
  pc->next=null;
  delete Lb;
}

