ElemType Max (LinkList L ){
  if(L->next==NULL) return NULL;
  pmax=L->next;
  p=L->next->next;
  while(p != NULL ){
    if(p->data > pmax->data) pmax=p;
    p=p->next;
  }
  return pmax->data;
}

void inverse(LinkList &L) {
