int compareTree(TreeNode* tree1, TreeNode* tree2){
  bool tree1IsNull = (tree1==NULL);
  bool tree2IsNull = (tree2==NULL);
  if(tree1IsNull != tree2IsNull) return 1;
  if(tree1IsNull && tree2IsNull) return 0;
  if(tree1->c != tree2->c) return 1;
