  else {
    BiTree Q[]; front=1;rear=1;last=1; temp=0; maxw=0;
    Q[rear]=bt;
    while(front<=last) {
      p=Q[front++]; temp++;
      if (p->lchild!=null) Q[++rear]=p->lchild;
      if (p->rchild!=null) Q[++rear]=p->rchild;
      if (front>last) { last=rear; if(temp>maxw) maxw=temp; temp=0; }
    }
    return (maxw);
  }
}

