}

void TwoWayBubbleSort(DLinkedList la){
  int exchange=1;
  head=la; tail=null;
  while (exchange){
    p=head->next; exchange=0;
    while (p->next!=tail) if (p->data>p->next->data) { ... exchange=1; } else p=p->next;
    tail=p; p=tail->prior;
    while (exchange && p->prior!=head) if (p->data<p->prior->data) { ... exchange=1; } else p=p->prior;
    head=p;
  }
}

